import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Prompt 入门","description":"","frontmatter":{},"headers":[],"relativePath":"prompting/basics.md","filePath":"prompting/basics.md","lastUpdated":1782223980000}'),s={name:"prompting/basics.md"};function o(p,a,n,r,d,c){return e(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="prompt-入门" tabindex="-1">Prompt 入门 <a class="header-anchor" href="#prompt-入门" aria-label="Permalink to &quot;Prompt 入门&quot;">​</a></h1><p>一句话：Prompt 是给模型的生成引导，不是绝对命令。好提示词要和模型生态、参数和工作流一起看。</p><h2 id="正向提示词" tabindex="-1">正向提示词 <a class="header-anchor" href="#正向提示词" aria-label="Permalink to &quot;正向提示词&quot;">​</a></h2><p>正向提示词写你希望出现的内容，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a quiet street at sunset, warm light, detailed background, cinematic composition</span></span></code></pre></div><p>常见信息包括：</p><ul><li>主体：人物、动物、建筑、物体。</li><li>场景：室内、街道、森林、海边。</li><li>风格：摄影、插画、动画截图、概念设计。</li><li>光线：柔光、逆光、霓虹、自然光。</li><li>构图：特写、全身、广角、俯视。</li><li>质量描述：清晰、细节丰富、干净背景。</li></ul><h2 id="负向提示词" tabindex="-1">负向提示词 <a class="header-anchor" href="#负向提示词" aria-label="Permalink to &quot;负向提示词&quot;">​</a></h2><p>负向提示词写你希望减少的内容，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>low quality, blurry, watermark, text, bad anatomy, extra fingers</span></span></code></pre></div><p>负向提示词不是万能修复器。它更适合减少常见问题，而不是强行让模型学会没学过的内容。</p><h2 id="标签式提示词" tabindex="-1">标签式提示词 <a class="header-anchor" href="#标签式提示词" aria-label="Permalink to &quot;标签式提示词&quot;">​</a></h2><p>二次元模型常见标签式写法，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1girl, solo, school uniform, long hair, blue eyes, classroom, soft lighting</span></span></code></pre></div><p>优点是简洁、可组合。缺点是需要了解模型训练时使用的标签体系。</p><h2 id="自然语言提示词" tabindex="-1">自然语言提示词 <a class="header-anchor" href="#自然语言提示词" aria-label="Permalink to &quot;自然语言提示词&quot;">​</a></h2><p>新一代模型通常更适合自然语言，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Create an illustration of a small robot reading a book in a cozy library, with warm lighting and a calm atmosphere.</span></span></code></pre></div><p>优点是描述清楚，适合复杂语义。缺点是如果模型不支持这种理解方式，效果可能不如标签。</p><h2 id="prompt-不跟手怎么办" tabindex="-1">Prompt 不跟手怎么办 <a class="header-anchor" href="#prompt-不跟手怎么办" aria-label="Permalink to &quot;Prompt 不跟手怎么办&quot;">​</a></h2><p>优先按顺序排查：</p><ol><li>底模是否适合这个题材。</li><li>提示词是否互相冲突。</li><li>是否需要触发词。</li><li>LoRA 权重是否过高。</li><li>CFG 是否过高或过低。</li><li>图片尺寸是否符合模型推荐。</li><li>是否需要 ControlNet、参考图或局部重绘。</li></ol><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>把所有好词都塞进去。过长提示词可能互相稀释。</li><li>复制别人的 prompt 但换了模型。不同模型理解方式不同。</li><li>忽略触发词。很多 LoRA 没有触发词就不明显。</li><li>只靠负向提示词修手。手部问题往往需要模型、LoRA、姿势控制或后期修复共同解决。</li></ul>',24)])])}const m=t(s,[["render",o]]);export{u as __pageData,m as default};
